spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var divisorX = W / 2 - 45;
    var startX = W / 2 - 15;
    var charW = 12;

    var rowQuotient = H / 2 - 45;
    var rowDividend = H / 2 - 25;
    var rowSub1 = H / 2 - 4;
    var rowLine1 = H / 2 + 7;
    var rowRem1 = H / 2 + 22;
    var rowSub2 = H / 2 + 42;
    var rowLine2 = H / 2 + 53;
    var rowRem2 = H / 2 + 68;

    // Stages
    // 0 - 2s: stage 1 (set up divisor, dividend and division box)
    // 2s - 4.5s: stage 2 (ones place division: 6 into 45 goes 7, remainder 3)
    // 4.5s - 7s: stage 3 (tenths place division: bring down 6, 6 into 36 goes 6)
    // 7s - 9.5s: stage 4 (decimal point floats up to quotient)
    // 9.5s - 12s: stage 5 (final result highlight)

    var stage = 1;
    if (progress >= 0.16 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.58) stage = 3;
    else if (progress >= 0.58 && progress < 0.79) stage = 4;
    else if (progress >= 0.79) stage = 5;

    ctx.font = 'bold 16px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Divisor 6
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('6', divisorX, rowDividend);

    // Division box lines
    ctx.beginPath();
    ctx.moveTo(divisorX + 10, rowDividend - 10);
    ctx.lineTo(divisorX + 10, rowDividend + 10);
    ctx.moveTo(divisorX + 10, rowDividend - 10);
    ctx.lineTo(startX + 45, rowDividend - 10);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 1.5;
    ctx.stroke();

    // Dividend: 45.6
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('4', startX, rowDividend);
    ctx.fillText('5', startX + charW, rowDividend);
    ctx.fillStyle = (stage === 1 || stage >= 4) ? '#EF4444' : '#F3F4F6'; // Highlight point
    ctx.fillText('.', startX + charW * 1.5, rowDividend);
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('6', startX + charW * 2, rowDividend);

    // Quotient steps
    if (stage >= 2) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('7', startX + charW, rowQuotient);
    }
    if (stage >= 3) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('6', startX + charW * 2, rowQuotient);
    }

    // Float decimal point animation in stage 4
    if (stage === 4) {
      var floatProg = (progress - 0.58) / 0.21;
      var currentY = rowDividend - floatProg * (rowDividend - rowQuotient);
      ctx.fillStyle = '#EF4444';
      ctx.fillText('.', startX + charW * 1.5, currentY);
    } else if (stage >= 5) {
      ctx.fillStyle = '#10B981'; // Final green decimal point in quotient
      ctx.fillText('.', startX + charW * 1.5, rowQuotient);
    }

    // Subtraction Step 1
    if (stage >= 2) {
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('-', startX - charW * 1.2, rowSub1);
      ctx.fillText('4', startX, rowSub1);
      ctx.fillText('2', startX + charW, rowSub1);

      ctx.beginPath();
      ctx.moveTo(startX - 5, rowLine1);
      ctx.lineTo(startX + charW + 5, rowLine1);
      ctx.strokeStyle = '#374151';
      ctx.lineWidth = 1;
      ctx.stroke();

      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('3', startX + charW, rowRem1);
    }

    // Subtraction Step 2
    if (stage >= 3) {
      // Bring down 6 arrow
      ctx.beginPath();
      ctx.moveTo(startX + charW * 2, rowDividend + 8);
      ctx.lineTo(startX + charW * 2, rowRem1 - 8);
      ctx.strokeStyle = '#3B82F6';
      ctx.lineWidth = 1;
      ctx.stroke();

      ctx.fillStyle = '#60A5FA';
      ctx.fillText('6', startX + charW * 2, rowRem1);

      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('-', startX + charW * 0.2, rowSub2);
      ctx.fillText('3', startX + charW, rowSub2);
      ctx.fillText('6', startX + charW * 2, rowSub2);

      ctx.beginPath();
      ctx.moveTo(startX + charW - 5, rowLine2);
      ctx.lineTo(startX + charW * 2 + 5, rowLine2);
      ctx.strokeStyle = '#374151';
      ctx.stroke();

      ctx.fillStyle = '#10B981';
      ctx.fillText('0', startX + charW * 2, rowRem2);
    }

    // Instructions
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Shifted Division setup: 45.6 ÷ 6', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Ignore the decimal place during column division', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Divide Ones: 45 ÷ 6', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('6 goes into 45 seven times: 7 × 6 = 42, remainder 3', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Bring down Tenths: 36 ÷ 6', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('6 goes into 36 six times: 6 × 6 = 36, remainder 0', W / 2, H - 22);
    } else if (stage === 4) {
      ctx.fillStyle = '#EF4444';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Float Decimal Point Upwards', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Move the decimal point straight up to the quotient row', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Quotient = 7.6', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Thus, original division: 4.56 ÷ 0.6 = 7.6', W / 2, H - 22);
    }
  }
};
